const keywords = [
  // SOLARSPEICHER – HOCH
  { keyword: 'Sungrow SBR', category: 'solarspeicher' },
  { keyword: 'BYD HVS Speicher', category: 'solarspeicher' },
  { keyword: 'BYD Battery Box', category: 'solarspeicher' },
  { keyword: 'Anker Solix Speicher', category: 'solarspeicher' },
  { keyword: 'Pylontech Speicher', category: 'solarspeicher' },
  { keyword: 'SENEC Speicher', category: 'solarspeicher' },
  { keyword: 'E3DC Hauskraftwerk', category: 'solarspeicher' },
  { keyword: 'Victron Speicher', category: 'solarspeicher' },
  // SOLARZAUN – HOCH
  { keyword: 'Solarzaun', category: 'solarzaun' },
  { keyword: 'PV Zaun bifazial', category: 'solarzaun' },
  { keyword: 'bifaziale Solarmodule Zaun', category: 'solarzaun' },
  // SOLARANLAGE + SPEICHER – MITTEL
  { keyword: 'Photovoltaik Komplettanlage Speicher', category: 'solaranlage' },
  { keyword: 'PV Anlage mit Speicher', category: 'solaranlage' },
  // WECHSELRICHTER – MITTEL
  { keyword: 'Sungrow Hybrid Wechselrichter', category: 'wechselrichter' },
  { keyword: 'Fronius Hybrid Wechselrichter', category: 'wechselrichter' },
  // BALKONKRAFTWERK + SPEICHER – MITTEL
  { keyword: 'Balkonkraftwerk Speicher', category: 'balkonkraftwerk' },
  { keyword: 'Anker Solix Balkonkraftwerk', category: 'balkonkraftwerk' },
];

return keywords.map(k => ({
  json: {
    keyword: k.keyword,
    category: k.category,
    maxAgeDays: MAX_AGE_DAYS,
    rssUrl: (function() {
      let slug = '';
      const lower = k.keyword.toLowerCase();
      for (let i = 0; i < lower.length; i++) {
        const code = lower.charCodeAt(i);
        if (lower[i] === ' ') { slug += '-'; }
        else if ((code >= 97 && code <= 122) || (code >= 48 && code <= 57)) { slug += lower[i]; }
      }
      return 'https://www.kleinanzeigen.de/s-' + slug + '/rss.html';
    })(),
  }
}));

const MAX_AGE_DAYS = 3;
const now = Date.now();
const maxAgeMs = MAX_AGE_DAYS * 24 * 60 * 60 * 1000;

function getTagContent(text, tag) {
  const open = '<' + tag + '>';
  const s = text.indexOf(open);
  if (s === -1) return '';
  const e = text.indexOf('</' + tag + '>', s);
  if (e === -1) return '';
  let content = text.substring(s + open.length, e).trim();
  if (content.indexOf('<![CDATA[') === 0) {
    const cdEnd = content.lastIndexOf(']]>');
    content = content.substring(9, cdEnd === -1 ? content.length : cdEnd).trim();
  }
  return content;
}

function stripHtml(html) {
  let result = '';
  let inTag = false;
  for (let i = 0; i < html.length; i++) {
    const ch = html[i];
    if (ch === '<') { inTag = true; continue; }
    if (ch === '>') { inTag = false; result += ' '; continue; }
    if (!inTag) result += ch;
  }
  let clean = '';
  let lastSpace = false;
  for (let i = 0; i < result.length; i++) {
    const code = result.charCodeAt(i);
    if (code === 32 || code === 10 || code === 13 || code === 9) {
      if (!lastSpace) { clean += ' '; lastSpace = true; }
    } else {
      clean += result[i]; lastSpace = false;
    }
  }
  return clean.trim();
}

function extractPrice(cleanText) {
  const euroIdx = cleanText.indexOf('\u20ac');
  if (euroIdx === -1) return null;
  let start = euroIdx - 1;
  while (start >= 0) {
    const c = cleanText.charCodeAt(start);
    if ((c >= 48 && c <= 57) || cleanText[start] === '.' || cleanText[start] === ',' || cleanText[start] === ' ') {
      start--;
    } else { break; }
  }
  let end = euroIdx + 2;
  if (cleanText.substring(end, end + 3) === ' VB') end += 3;
  const candidate = cleanText.substring(start + 1, end).trim();
  let hasDigit = false;
  for (let i = 0; i < candidate.length; i++) {
    if (candidate.charCodeAt(i) >= 48 && candidate.charCodeAt(i) <= 57) { hasDigit = true; break; }
  }
  return (hasDigit && candidate.length < 30) ? candidate : null;
}

function parseRssItems(xml) {
  const seen = new Set();
  const listings = [];
  let pos = 0;
  while (pos < xml.length) {
    const itemStart = xml.indexOf('<item>', pos);
    if (itemStart === -1) break;
    const itemEnd = xml.indexOf('</item>', itemStart);
    if (itemEnd === -1) break;
    const item = xml.substring(itemStart + 6, itemEnd);
    pos = itemEnd + 7;
    const pubDateStr = getTagContent(item, 'pubDate');
    if (pubDateStr) {
      const pubTs = new Date(pubDateStr).getTime();
      if (!isNaN(pubTs) && now - pubTs > maxAgeMs) continue;
    }
    const link = getTagContent(item, 'link');
    const title = getTagContent(item, 'title');
    const descClean = stripHtml(getTagContent(item, 'description'));
    let adId = null;
    for (const seg of link.split('?')[0].split('#')[0].split('/')) {
      const part = seg.split('-')[0];
      if (part.length >= 7 && part.length <= 12) {
        let isNum = true;
        for (let i = 0; i < part.length; i++) {
          const c = part.charCodeAt(i);
          if (c < 48 || c > 57) { isNum = false; break; }
        }
        if (isNum) { adId = part; break; }
      }
    }
    if (!adId || !title) continue;
    if (seen.has(adId)) continue;
    seen.add(adId);
    listings.push({
      adId, title,
      price: extractPrice(descClean),
      description: descClean || null,
      location: null, plz: null,
      date: pubDateStr || null,
      url: link || null,
      image: null, shipping: null,
    });
  }
  return listings;
}

// Alle 17 Keywords + RSS-Responses paarweise verarbeiten
const keywordItems = $('Keywords laden').all();
const rssItems = $input.all();
const results = [];

for (let i = 0; i < rssItems.length; i++) {
  const kwItem = keywordItems[i];
  const keyword = kwItem ? kwItem.json.keyword : 'unknown';
  const category = kwItem ? kwItem.json.category : '';
  const rssJson = rssItems[i].json;
  const xml = String(rssJson.data || rssJson || '');
  const listings = parseRssItems(xml);
  results.push({
    json: {
      source: 'kleinanzeigen',
      keyword,
      category,
      listingCount: listings.length,
      listings,
    }
  });
}

return results;
